def llist_of_values_left_to_right(exps, env):
    if is_none(exps):
        return None
    else:
        first = evaluate(head(exps), env)
        rest = llist_of_values_left_to_right(tail(exps), env)
        return pair(first, rest)

def llist_of_values_right_to_left(exps, env):
    if is_none(exps):
        return None
    else:
        rest = llist_of_values_right_to_left(tail(exps), env)
        first = evaluate(head(exps), env)
        return pair(first, rest)

